      "type": "array",
      "items": {
        "$ref": "#/$defs/FulfillmentAssessment"
      }
    },
    "overall_fulfillment": {
      "type": "object",
      "minProperties": 1
    },
    "expected": {},
    "missing": {
      "type": "array",
      "items": {
        "$ref": "#/$defs/GapItem"
      }
    },
    "wrong": {
      "type": "array",
      "items": {
        "$ref": "#/$defs/GapItem"
      }
    },
    "extra": {
      "type": "array",
      "items": {
        "$ref": "#/$defs/GapItem"
      }
    },
    "evidence": {
      "type": "array",
      "items": {}
    },
    "reasoning_summary": {
      "type": "string",
      "minLength": 1
    }
  },
  "additionalProperties": false,
  "$defs": {
    "BusinessExpectation": {
      "type": "object",
      "properties": {
        "expectation_id": {
          "type": "string",
          "minLength": 1
        },
