        "答案中明确给出赔付比例区间（如20%至30%）"
      ],
      "priority": "high"
    },
    {
      "expectation_id": "说明赔付次数上限和间隔期",
      "user_intent": "用户可能关心赔付是否有次数和时限限制",
      "expected_outcome": "提及可能存在赔付次数上限（如3次或5次）以及两次赔付之间的间隔期要求",
      "acceptance_criteria": [
        "答案中提到了次数上限（如3次或5次）以及间隔期"
      ],
      "priority": "medium"
    },
    {
      "expectation_id": "建议查阅合同以获取准确信息",
      "user_intent": "避免用户将通用解答误解为合同承诺",
      "expected_outcome": "明确提示用户查阅自身保险合同条款或咨询客服",
      "acceptance_criteria": [
        "答案中包含“建议查阅您的保险合同条款”或等同的提示语句"
      ],
      "priority": "high"
    },
    {
      "expectation_id": "关键信息与参考答案一致",
      "user_intent": "确保提供给用户的核心数据（比例、次数等）准确无误",
      "expected_outcome": "答案中出现的数字、是否存在间隔期等信息与参考答案无冲突",
      "acceptance_criteria": [
        "多次赔付的可能性与参考答案一致",
        "赔付比例20%-30%与参考答案一致",
        "次数上限3-5次与参考答案一致",
        "存在间隔期要求与参考答案一致"
      ],
      "priority": "high"
    },
    {
      "expectation_id": "使用非绝对化表述避免误导",
      "user_intent": "答案应承认个体合同差异，避免作出保证性承诺",
      "expected_outcome": "采用“一般情况下”“通常”“可能”等限定词，并开篇声明取决于合同",
      "acceptance_criteria": [
        "答案开篇或较早位置声明赔付规则取决于具体合同",
        "文中使用“通常”“可能”等非绝对化词语"
      ],
      "priority": "medium"
    }
  ],
  "fulfillment_assessments": [
    {
      "expectation_id": "回答轻症能否多次赔付",
      "status": "fulfilled",
