      "blocking": false,
      "confidence": 0.99
    },
    {
      "expectation_id": "提供每次赔付金额比例",
      "status": "fulfilled",
      "score": 1.0,
      "actual_evidence": [
        "实际输出中写明：“每次赔付金额通常为基本保险金额的20%至30%”。"
      ],
