      "blocking": false,
      "confidence": 0.99
    },
    {
      "expectation_id": "说明赔付次数上限和间隔期",
      "status": "fulfilled",
      "score": 1.0,
      "actual_evidence": [
        "实际输出包含：“且可能有次数上限（如3次或5次）和间隔期要求”。"
      ],
      "downstream_impact": "用户对赔付存在的常见限制（次数、时间间隔）有了基本认知，有助于后续查阅合同。",
      "blocking": false,
      "confidence": 0.99
    },
    {
      "expectation_id": "建议查阅合同以获取准确信息",
      "status": "fulfilled",
      "score": 1.0,
      "actual_evidence": [
        "实际输出末尾明确建议：“建议查阅您的保险合同条款获取准确信息”。"
      ],
      "downstream_impact": "引导用户以合同为准，降低了因通用解答引发误解的风险。",
      "blocking": false,
      "confidence": 0.99
    },
